import { readFileSync } from 'node:fs';
const flags=readFileSync('packages/agent-core/src/flags/registry.ts','utf8');
const dream=readFileSync('packages/agent-core/src/agent/dream/auto-dream.ts','utf8');
const fails=[];
const idx=flags.indexOf("id: 'auto_dream'");
if (idx < 0) fails.push('flag-id');
const block=flags.slice(idx, idx+400);
if (!block.includes('default: true')) fails.push('default-true');
if (!dream.includes('class AutoDreamService')) fails.push('service-missing');
if (fails.length){console.error(fails.join(',')); process.exit(1);} console.log('auto-dream-source-ok');
